import React from 'react';
import { IAP, Item } from '@hughsk/react-native-iap';

class PaymentModule extends React.Component {
  constructor(props) {
    super(props);
    this.state = { purchased: false };
  }
  
  componentDidMount() {
    IAP.init();
    
    // Listen to purchase success event
    this._purchaseSuccessListener = (details) => {
      if (details.productId == "yourProductID") {
        this.setState({ purchased: true });
      }
    };
  
    IAP.when('Purchase').wasSuccessful().listen(this._purchaseSuccessListener);
  }
  
  componentWillUnmount() {
    // Stop listening to purchase events
    if (this._purchaseSuccessListener) this._purchaseSuccessListener.remove();
  }
  
  buy = () => {
    IAP.requestPurchase('yourProductID');
  };
  
  render() {
    return (
      <Button title="Buy Me!" onPress={this.buy} />
    );
  }
}

export default PaymentModule;